import json

def json_formatter(text: str, pretty: bool = True) -> str:
    try:
        obj = json.loads(text)
        if pretty:
            return json.dumps(obj, ensure_ascii=False, indent=2)
        return json.dumps(obj, separators=(',', ':'))
    except Exception as e:
        return f"JSON解析错误: {e}"

